/**
 * Seed: Social-cluster blog posts (Batch 4) — party, friendship, congratulations, thank-you.
 * 3 posts per occasion (12 total), English.
 *
 * Run: npx tsx -r dotenv/config scripts/seed-social-cluster-blogs.ts dotenv_config_path=.env.local
 *
 * Idempotent: skips any slug that already exists.
 *
 * Note: `content` is stored HTML-entity-encoded as produced by the content
 * writers; `decode()` converts it to raw HTML before inserting, so the blog
 * pages render real markup (not visible &lt;p&gt; text).
 */

import 'dotenv/config';
import { db } from '../src/lib/db';
import { blogPostsTable } from '../src/lib/db/schema';
import { eq } from 'drizzle-orm';

interface BlogPost {
  title: string;
  slug: string;
  meta_description: string;
  content: string;
  category: string;
}

/** Decode the limited set of HTML entities present in the seeded content. */
function decode(html: string): string {
  return html
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&amp;/g, '&');
}

